import {useCallback, useEffect, useMemo, useState} from "react";
import {countries} from "../../../third-parties";
import {phone_masks} from "../../../third-parties/phone_masks";

// ── Types ──────────────────────────────────────────────────────────────

interface CountryEntry {
    name: string;
    code: string;
    iso: string;
    flag: string;
    mask: string | string[];
}

export interface PhoneOutputObject {
    countryCode: string;
    nationalNumber: string;
    internationalFormatted: string;
    nationalFormatted: string;
    iso: string;
}

interface UsePhoneInputOptions {
    value?: any;
    onChange?: (value: any) => void;
    outputFormat?: 'string' | 'object';
    isWithCountryCode?: boolean;
    defaultCountry?: string;
    includedCountries?: string[];
    excludedCountries?: string[];
}

interface UsePhoneInputReturn {
    displayValue: string;
    e164Value: string;
    objectValue: PhoneOutputObject | null;
    countryISO: string | null;
    countryFlagUrl: string | null;
    handleChange: (raw: string) => void;
}

// ── Helpers (module-level, computed once) ────────────────────────────

const dialCodeMap: Map<string, CountryEntry[]> = (() => {
    const map = new Map<string, CountryEntry[]>();
    for (const country of countries) {
        const existing = map.get(country.code) ?? [];
        existing.push(country as CountryEntry);
        map.set(country.code, existing);
    }
    return map;
})();

const sortedDialCodes: string[] = Array.from(dialCodeMap.keys()).sort(
    (a, b) => b.length - a.length,
);

const isoMap: Map<string, CountryEntry> = (() => {
    const map = new Map<string, CountryEntry>();
    for (const country of countries) {
        map.set(country.iso, country as CountryEntry);
    }
    return map;
})();

const isoMaskMap: Record<string, string> = phone_masks;

// ── Pure utilities ──────────────────────────────────────────────────

function extractDigits(str: string): string {
    return str.replace(/\D/g, "");
}

/**
 * Normalize ANY incoming value shape to a raw digit string.
 * Handles: E.164 strings, legacy {phone, code} objects, IPhoneObjectValue objects, plain strings.
 */
function normalizeIncomingValue(value: any): string {
    if (!value) return "";
    if (typeof value === "string") return value;
    if (typeof value === "object") {
        // IPhoneObjectValue: { countryCode, nationalNumber, ... }
        if ("countryCode" in value && "nationalNumber" in value) {
            const national = extractDigits(value.nationalNumber);
            return value.countryCode ? `+${value.countryCode}${national}` : national;
        }
        // Legacy {phone, code}
        if ("phone" in value && "code" in value) {
            const digits = extractDigits(value.phone);
            return value.code ? `+${value.code}${digits}` : digits;
        }
    }
    return String(value);
}

function detectCountryFromDigits(
    digits: string,
    defaultCountry: string,
    filteredISOs: Set<string> | null,
): CountryEntry | null {
    if (!digits) return null;

    for (const code of sortedDialCodes) {
        if (digits.startsWith(code)) {
            const entries = dialCodeMap.get(code)!;
            const candidates = filteredISOs
                ? entries.filter((e) => filteredISOs.has(e.iso))
                : entries;

            if (candidates.length === 0) continue;
            if (candidates.length === 1) return candidates[0] ?? null;

            const preferred = candidates.find((e) => e.iso === defaultCountry);
            return preferred ?? candidates[0] ?? null;
        }
    }
    return null;
}

/**
 * Format digits into a mask pattern.
 * Mask uses "9" as digit placeholder; literal digits (e.g. the country code
 * embedded in the mask like "+61-...") are matched and consumed from the input.
 */
function formatWithMask(digits: string, mask: string): string {
    let result = "";
    let digitIndex = 0;

    for (let i = 0; i < mask.length; i++) {
        if (digitIndex >= digits.length) break;

        const maskChar = mask[i]!;

        if (maskChar === "9") {
            result += digits[digitIndex];
            digitIndex++;
        } else if (/\d/.test(maskChar)) {
            if (digits[digitIndex] === maskChar) {
                digitIndex++;
            }
            result += maskChar;
        } else {
            result += maskChar;
        }
    }

    if (digitIndex < digits.length) {
        result += digits.slice(digitIndex);
    }

    return result;
}

/**
 * Derive the national formatted string from the international formatted string.
 * Strips the country code prefix and leading separator from the formatted output.
 * E.g.: internationalFormatted="+61-4-1234-5678", countryCode="61" → "4-1234-5678"
 */
function deriveNationalFormatted(internationalFormatted: string, countryCode: string): string {
    // Find where the country code digits end in the formatted string
    let pos = 0;
    let codeDigitsConsumed = 0;

    // Skip the leading "+"
    if (internationalFormatted[pos] === "+") pos++;

    // Consume all chars that are part of the country code (digits + formatting chars between them)
    while (pos < internationalFormatted.length && codeDigitsConsumed < countryCode.length) {
        const ch = internationalFormatted[pos]!;
        if (/\d/.test(ch)) {
            codeDigitsConsumed++;
        }
        pos++;
    }

    // Skip any trailing separator after the country code (-, space, (, ))
    while (pos < internationalFormatted.length && /[\s\-()]/.test(internationalFormatted[pos]!)) {
        pos++;
    }

    return internationalFormatted.slice(pos);
}

function toE164(input: string): string {
    const digits = extractDigits(input);
    if (!digits) return "";
    return `+${digits}`;
}

// ── Hook ────────────────────────────────────────────────────────────

export function usePhoneInput({
    value,
    onChange,
    outputFormat = "string",
    isWithCountryCode,
    defaultCountry = "US",
    includedCountries,
    excludedCountries,
}: UsePhoneInputOptions): UsePhoneInputReturn {

    const filteredISOs = useMemo<Set<string> | null>(() => {
        if (!includedCountries?.length && !excludedCountries?.length) return null;

        let isos = new Set(isoMap.keys());

        if (includedCountries?.length) {
            const included = new Set<string>();
            for (const c of countries) {
                if (includedCountries.includes(c.iso) || includedCountries.includes(c.name)) {
                    included.add(c.iso);
                }
            }
            isos = included;
        }

        if (excludedCountries?.length) {
            for (const c of countries) {
                if (excludedCountries.includes(c.iso) || excludedCountries.includes(c.name)) {
                    isos.delete(c.iso);
                }
            }
        }

        return isos;
    }, [includedCountries, excludedCountries]);

    const [rawDigits, setRawDigits] = useState<string>(() =>
        extractDigits(normalizeIncomingValue(value)),
    );

    // Sync with external value changes
    useEffect(() => {
        const normalized = normalizeIncomingValue(value);
        const digits = extractDigits(normalized);
        setRawDigits(digits);
    }, [value]);

    const detectedCountry = useMemo<CountryEntry | null>(() => {
        if (!isWithCountryCode || !rawDigits) {
            if (isWithCountryCode && defaultCountry) {
                return isoMap.get(defaultCountry) ?? null;
            }
            return null;
        }
        return detectCountryFromDigits(rawDigits, defaultCountry, filteredISOs);
    }, [rawDigits, isWithCountryCode, defaultCountry, filteredISOs]);

    // International formatted display value
    const displayValue = useMemo<string>(() => {
        if (!rawDigits) return "";

        if (!isWithCountryCode) return rawDigits;

        if (detectedCountry) {
            const mask = isoMaskMap[detectedCountry.iso];
            if (mask) return formatWithMask(rawDigits, mask);
        }

        return `+${rawDigits}`;
    }, [rawDigits, isWithCountryCode, detectedCountry]);

    const e164Value = useMemo<string>(() => {
        if (!rawDigits) return "";
        return `+${rawDigits}`;
    }, [rawDigits]);

    // Build the structured object output
    const objectValue = useMemo<PhoneOutputObject | null>(() => {
        if (!rawDigits || !isWithCountryCode || !detectedCountry) return null;

        const countryCode = detectedCountry.code;
        const nationalNumber = rawDigits.startsWith(countryCode)
            ? rawDigits.slice(countryCode.length)
            : rawDigits;

        const internationalFormatted = displayValue;
        const nationalFormatted = deriveNationalFormatted(internationalFormatted, countryCode);

        return {
            countryCode,
            nationalNumber,
            internationalFormatted,
            nationalFormatted,
            iso: detectedCountry.iso,
        };
    }, [rawDigits, isWithCountryCode, detectedCountry, displayValue]);

    const handleChange = useCallback(
        (raw: string) => {
            const digits = extractDigits(raw);
            setRawDigits(digits);

            if (!isWithCountryCode) {
                onChange?.(digits);
                return;
            }

            if (outputFormat === "object") {
                // Build object output inline for the onChange callback
                // (can't use objectValue memo — it hasn't updated yet with new digits)
                const country = detectCountryFromDigits(digits, defaultCountry, filteredISOs);
                if (country && digits) {
                    const cc = country.code;
                    const national = digits.startsWith(cc) ? digits.slice(cc.length) : digits;
                    const mask = isoMaskMap[country.iso];
                    const intlFormatted = mask ? formatWithMask(digits, mask) : `+${digits}`;
                    const natFormatted = deriveNationalFormatted(intlFormatted, cc);

                    onChange?.({
                        countryCode: cc,
                        nationalNumber: national,
                        internationalFormatted: intlFormatted,
                        nationalFormatted: natFormatted,
                        iso: country.iso,
                    });
                } else {
                    onChange?.({
                        countryCode: "",
                        nationalNumber: digits,
                        internationalFormatted: digits ? `+${digits}` : "",
                        nationalFormatted: digits,
                        iso: "",
                    });
                }
            } else {
                const e164 = digits ? `+${digits}` : "";
                onChange?.(e164);
            }
        },
        [isWithCountryCode, outputFormat, onChange, defaultCountry, filteredISOs],
    );

    return {
        displayValue,
        e164Value,
        objectValue,
        countryISO: detectedCountry?.iso ?? null,
        countryFlagUrl: detectedCountry?.flag ?? null,
        handleChange,
    };
}

export {normalizeIncomingValue, toE164, extractDigits};
